import React from 'react';
import '../css/RoomCard.css'; 

const RoomCard = React.memo(function RoomCard({ room, onSelect, isBooked }) {
  // Fix: Just check if room.image exists. 
  // Most bundlers return a string or an object with a default property.
  const imageSrc = typeof room.image === 'object' ? room.image.default : room.image;

  return (
    <div className="card" onClick={() => onSelect(room)}>
      {isBooked && <div className="bookedBadge">BOOKED</div>}

      <div className="img-container">
        {imageSrc ? (
          <img 
            src={imageSrc} 
            alt={room.name} 
            className="img-file" 
            onError={(e) => { e.target.style.display = 'none'; }} // Fallback if image path is broken
          />
        ) : (
          <div className="placeholder-icon">🏨</div>
        )}
      </div>

      <div className="body">
        <div className="type">{room.type}</div>
        <div className="name">{room.name}</div>
        <div className="amenities">
          {room.amenities.map((a) => (
            <span key={a} className="tag">
              {a}
            </span>
          ))}
        </div>
        <div className="footer">
          <div>
            <span className="price">₹{room.price.toLocaleString()}</span>
            <span className="per"> /night</span>
          </div>
          <span className="capacity">
            👤 {room.capacity} {room.capacity > 1 ? 'guests' : 'guest'}
          </span>
        </div>
      </div>
    </div>
  );
});

export default RoomCard;
